// ==============================================================================
// ADVANCED FUSION & VISUALS ENGINE
// This node merges two distinct APIs and generates dynamic visual themes.
// ==============================================================================

// 1. Data Ingestion: Capture input from ALL previous nodes
const weatherData = $items("Weather Data Ingestion")[0].json; // Fetch by node name
const aqiDataRaw = $items("Air Pollution Data Ingestion")[0].json; // Fetch by node name

// 2. Data Synthesis: Merge the core results
const mergedData = {
  city: weatherData.name,
  temperature: Math.round(weatherData.main.temp),
  conditionMain: weatherData.weather[0].main, // "Clear", "Rain", etc.
  conditionDesc: weatherData.weather[0].description, // "light rain"
  aqiValue: aqiDataRaw.list[0].main.aqi // 1-5 Scale
};

// ==============================================================================
// VISUAL ENGINE: DEFINE COLOR THEMES BASED ON WEATHER (Logic Path)
// ==============================================================================
let themeColor;
const mainSky = mergedData.conditionMain.toLowerCase();

if (mainSky.includes('clear')) {
  // Clear Skies: Warm Orange theme
  themeColor = "#FF8C00"; 
} else if (mainSky.includes('cloud')) {
  // Cloudy: Neutral Slate Gray theme
  themeColor = "#778899";
} else if (mainSky.includes('rain') || mainSky.includes('drizzle')) {
  // Rain/Drizzle: Cool Blues theme
  themeColor = "#1E90FF";
} else if (mainSky.includes('thunder') || mainSky.includes('storm')) {
  // Thunderstorm: Dark Electric theme
  themeColor = "#4B0082";
} else if (mainSky.includes('snow') || mainSky.includes('mist') || mainSky.includes('haze')) {
  // Snow/Mist/Haze: Soft Whites and Silvers
  themeColor = "#F0F8FF"; 
} else {
  // Default fallback (e.g., Extreme cases): Safe dark theme
  themeColor = "#333333";
}

// ==============================================================================
// LOGIC ENGINE: CLASSIFY AIR QUALITY & GENERATE ADVICE
// ==============================================================================
let aqiRating, aqiColor, aqiAdvice;
const rawAqi = mergedData.aqiValue;

switch (rawAqi) {
  case 1:
    aqRating = "Good";
    aqiColor = "#00C853"; // Vibrant Green
    aqiAdvice = "Air is fresh and clean. Enjoy your outdoor commute!";
    break;
  case 2:
    aqRating = "Fair";
    aqiColor = "#FBC02D"; // Rich Yellow
    aqiAdvice = "Air is acceptable, but sensitive groups should minimize extended outdoor time.";
    break;
  case 3:
    aqRating = "Moderate";
    aqiColor = "#FF9800"; // Clean Orange
    aqiAdvice = "General population may experience minor discomfort. Consider indoor activity if sensitive.";
    break;
  case 4:
    aqRating = "Poor";
    aqiColor = "#F44336"; // Solid Red
    aqiAdvice = "General population should avoid prolonged outdoor exertion. Sensitive groups stay indoors.";
    break;
  case 5:
    aqRating = "Very Poor";
    aqiColor = "#B71C1C"; // Deep Dark Red
    aqiAdvice = "EMERGENCY ALERT: Air quality is hazardous. All individuals must avoid any outdoor physical activity.";
    break;
  default:
    aqRating = "Data Error";
    aqiColor = "#CCCCCC"; // Neutral Gray
    aqiAdvice = "Air quality data currently unavailable.";
}

// ==============================================================================
// RETURN CONSOLIDATED PAYLOAD FOR THE EMAIL NODE
// ==============================================================================
return {
  json: {
    city: mergedData.city,
    temperature: mergedData.temperature,
    condition: mergedData.conditionDesc,

    // Dynamic Visuals Data
    themeColor: themeColor,
    iconUrl: 'https://openweathermap.org/img/wn/' + weatherData.weather[0].icon + '@2x.png',

    // Advanced Data Data
    airQualityStatus: aqRating,
    airQualityColor: aqiColor,
    airQualityAdvice: aqiAdvice
  }
};
